INSERT INTO "public"."services" ("id", "name", "description", "price", "duration_minutes", "features", "active", "created_at", "images") VALUES
	('7412f20a-1a20-4fa6-aa8a-0c25990d6598', 'Glow In The Dark', 'Perfect for small gatherings! A fun-filled hour of bubbles and laughter for up to 15 kids.', 400.00, 60, '["60 min of non stop Glowing Foam", "1 bubble machine", "Glowing Face Paint", "Non stop music", "1 hour of fun"]', true, '2026-03-04 04:09:54.709034+00', '[]'),
	('19f593bf-8ebe-4ef1-83f0-d8c1d83e3e78', 'Foam Party', 'Our most popular package! One hour of non-stop bubble magic with foam pit action.', 349.00, 60, '["Up to 30 kids", "1 bubble machines", "1 hour of fun"]', true, '2026-03-04 04:09:54.709034+00', '[]'),
	('d685e6e9-67ff-4b72-9102-316b34f5c6a7', 'Bubble Birthday Special', 'Make their birthday unforgettable with our all-inclusive bubble birthday package!', 449.00, 150, '["Up to 40 kids", "4 bubble machines", "Foam pit", "Birthday decorations", "Bubble-themed party favors", "2.5 hours of fun"]', false, '2026-03-04 04:09:54.709034+00', '[]'),
	('a1088228-e71f-40f6-b904-90f5039a7df8', 'Foam Frenzy Deluxe', 'The ultimate bubble and foam experience! Perfect for large events and celebrations.', 749.00, 180, '["Up to 50 kids", "3 bubble machines", "Giant foam pit", "LED bubble show", "3 hours of fun", "Event coordinator"]', true, '2026-03-04 04:09:54.709034+00', '[]');
